onClick:
{{
  (function() {
    if (!sel_customer.selectedOptionValue) {
      showAlert('Please select a customer', 'warning');
      return;
    }
    if (!sel_job_type.selectedOptionValue) {
      showAlert('Please select a job type', 'warning');
      return;
    }
    if (!dp_collection_date.selectedDate) {
      showAlert('Please set a collection date', 'warning');
      return;
    }
    if (!tbl_sites.selectedRow?.site_id) {
      showAlert('Please select a collection site', 'warning');
      return;
    }
    qry_collection_create.run(
      function(result) {
        var newCollectionId = result?.[0]?.collection_id;
        if (!newCollectionId) {
          showAlert('Collection created, but could not read its ID', 'warning');
          navigateTo('Home', {}, 'SAME_WINDOW');
          return;
        }
        storeValue('newCollectionId', newCollectionId).then(function() {
          // TODO: REVIEW BEFORE GO-LIVE
          // Asset refs (e.g. 559-00001) are generated at booking time using the collection_id as prefix.
          // Assumption: qry_create_collection_asset_ref is NOT needed here as asset_ref
          // is only written to the assets table when an asset is booked into this collection.
          // If assets can exist without going through the booking page, this may need revisiting.
          // Original query removed: qry_create_collection_asset_ref.run()
          showAlert('Collection created successfully', 'success');
          navigateTo('Collection_job_View', { collectionId: newCollectionId }, 'SAME_WINDOW');
        });
      },
      function(error) {
        showAlert('Failed to create collection — ' + (error?.message || 'unknown error'), 'error');
      }
    );
  })()
}}
